# @cctt_verify {"v":2,"sym":"sympy.diffgeom.tests.test_hyperbolic_space.test_H2","kind":"function","src_hash":"87994008c59ee06d","in":{"base":"Any"},"out":{"base":"Any","pred":"mat == automat and gamma1[0, 0, 0] == 0 and gamma1[0, 0, 1] == -y ** (-3) and gamma1[0, 1, 0] == -y ** (-3) and gamma1[0, 1, 1] == 0 and gamma1[1, 1, 1] == -y ** (-3) and gamma1[1, 1, 0] == 0 and gamma1[1, 0, 1] == 0 and gamma1[1, 0, 0] == y ** (-3) and gamma2[0, 0, 0] == 0 and gamma2[0, 0, 1] == -y ** (-1) and gamma2[0, 1, 0] == -y ** (-1) and gamma2[0, 1, 1] == 0 and gamma2[1, 1, 1] == -y ** (-1) and gamma2[1, 1, 0] == 0 and gamma2[1, 0, 1] == 0 and gamma2[1, 0, 0] == y ** (-1) and Rm[0, 0, 0, 0] == 0 and Rm[0, 0, 0, 1] == 0 and Rm[0, 0, 1, 0] == 0 and Rm[0, 0, 1, 1] == 0 and Rm[0, 1, 0, 0] == 0 and Rm[0, 1, 0, 1] == -y ** (-2) and Rm[0, 1, 1, 0] == y ** (-2) and Rm[0, 1, 1, 1] == 0 and Rm[1, 0, 0, 0] == 0 and Rm[1, 0, 0, 1] == y ** (-2) and Rm[1, 0, 1, 0] == -y ** (-2) and Rm[1, 0, 1, 1] == 0 and Rm[1, 1, 0, 0] == 0 and Rm[1, 1, 0, 1] == 0 and Rm[1, 1, 1, 0] == 0 and Rm[1, 1, 1, 1] == 0 and Ric[0, 0] == -y ** (-2) and Ric[0, 1] == 0 and Ric[1, 0] == 0 and Ric[0, 0] == -y ** (-2) and Ric == ImmutableDenseNDimArray([-y ** (-2), 0, 0, -y ** (-2)], (2, 2)) and R == -2 and R / 2 == -1"},"spec":{"lhs":"test_H2()","rhs":"test_H2 produces the expected output","over":{"base":"Any"},"name":"test_H2_correct"},"guarantee":"test_H2 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.diffgeom.tests.test_hyperbolic_space.test_H2_correct","statement":"Path(test_H2(x), test_H2 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"e0d8d35447e82b89"}
def test_H2():
    TP = sympy.diffgeom.TensorProduct
    R2 = sympy.diffgeom.rn.R2
    y = R2.y
    dy = R2.dy
    dx = R2.dx
    g = (TP(dx, dx) + TP(dy, dy))*y**(-2)
    automat = twoform_to_matrix(g)
    mat = diag(y**(-2), y**(-2))
    assert mat == automat

    gamma1 = metric_to_Christoffel_1st(g)
    assert gamma1[0, 0, 0] == 0
    assert gamma1[0, 0, 1] == -y**(-3)
    assert gamma1[0, 1, 0] == -y**(-3)
    assert gamma1[0, 1, 1] == 0

    assert gamma1[1, 1, 1] == -y**(-3)
    assert gamma1[1, 1, 0] == 0
    assert gamma1[1, 0, 1] == 0
    assert gamma1[1, 0, 0] == y**(-3)

    gamma2 = metric_to_Christoffel_2nd(g)
    assert gamma2[0, 0, 0] == 0
    assert gamma2[0, 0, 1] == -y**(-1)
    assert gamma2[0, 1, 0] == -y**(-1)
    assert gamma2[0, 1, 1] == 0

    assert gamma2[1, 1, 1] == -y**(-1)
    assert gamma2[1, 1, 0] == 0
    assert gamma2[1, 0, 1] == 0
    assert gamma2[1, 0, 0] == y**(-1)

    Rm = metric_to_Riemann_components(g)
    assert Rm[0, 0, 0, 0] == 0
    assert Rm[0, 0, 0, 1] == 0
    assert Rm[0, 0, 1, 0] == 0
    assert Rm[0, 0, 1, 1] == 0

    assert Rm[0, 1, 0, 0] == 0
    assert Rm[0, 1, 0, 1] == -y**(-2)
    assert Rm[0, 1, 1, 0] == y**(-2)
    assert Rm[0, 1, 1, 1] == 0

    assert Rm[1, 0, 0, 0] == 0
    assert Rm[1, 0, 0, 1] == y**(-2)
    assert Rm[1, 0, 1, 0] == -y**(-2)
    assert Rm[1, 0, 1, 1] == 0

    assert Rm[1, 1, 0, 0] == 0
    assert Rm[1, 1, 0, 1] == 0
    assert Rm[1, 1, 1, 0] == 0
    assert Rm[1, 1, 1, 1] == 0

    Ric = metric_to_Ricci_components(g)
    assert Ric[0, 0] == -y**(-2)
    assert Ric[0, 1] == 0
    assert Ric[1, 0] == 0
    assert Ric[0, 0] == -y**(-2)

    assert Ric == ImmutableDenseNDimArray([-y**(-2), 0, 0, -y**(-2)], (2, 2))

    ## scalar curvature is -2
    #TODO - it would be nice to have index contraction built-in
    R = (Ric[0, 0] + Ric[1, 1])*y**2
    assert R == -2

    ## Gauss curvature is -1
    assert R/2 == -1
